head.script:
// 전역변수
scwin.memJson = $c.data.getMemInfo();
scwin.vLoginCoCd 		= $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd; // 소속 자회사  	
scwin.vLoginCoClsCd 	= $c.gus.cfIsNull(scwin.memJson.coClsCd)?'':scwin.memJson.coClsCd;//회계_회사구분('CO035' : 0:동부 EXPRESS)	
scwin.vUserHomeClsCd	= scwin.memJson.userHomeClsCd;        // 사용자소속구분코드 	
scwin.vCoCd             = $c.gus.cfIsNull(scwin.memJson.coCd)?'':scwin.memJson.coCd; // 회사코드
scwin.isSubCompany = false;
scwin.isStart = false;

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
	$c.gus.cfDisableKey();
};

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
    ica_FromDate.setValue($c.date.getServerDateTime("yyyy"));
    scwin.f_setCompanyInfo();
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function()	{   
     // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    scwin.isStart = true;
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
}

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function(pWinCloseTF) {
    await udc_dongbuGroupCompanyInfo.cfCommonPopUp(scwin.udc_dongbuGroupCompanyInfo_callBackFunc,ed_coCd.getValue(), ed_coNm.getValue(), pWinCloseTF,null,null,null,null
										,null,null,null,null,null);
};

scwin.udc_dongbuGroupCompanyInfo_callBackFunc = function(rtnList) {
    // SET	
    if (rtnList != null) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue(rtnList[0]);   // 코드
        ed_coNm.setValue(rtnList[5]);   // 회사명 
        scwin.txtCoClsCd = rtnList[1];  // 회사구분
    } else {
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    if (scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU) {  // 자회사 회계 시스템 
        scwin.isSubCompany = true;
    } else {
        scwin.isSubCompany = false;
    }

    if(scwin.isStart == true) {
        if ('T' == scwin.privAdmin || !scwin.isSubCompany) {    // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
            $c.gus.cfEnableObjects([ed_coCd, ed_coNm, btn_company]);
        } else {
            $c.gus.cfDisableObjects([ed_coCd, ed_coNm, btn_company]);
        }
    }

    scwin.isStart = false;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    // 필수입력 사항 확인
    let ret = await $c.gus.cfValidate([ed_coCd,ica_FromDate]);
    if(!ret) {
        return false;
    }

    const params = {
        closeYm: ica_FromDate.getValue().trim()+"00", 
        closeDd: "00",
        mgntNo: "0",
        wrkNo: ACConstants.CLOSE_BUDGET_CREATION
    };

    //데이터셋에 정보설정
    dma_searchBudgetCreate.setJSON(params);

	$c.sbm.execute(sbm_searchBudgetCreate);

}

//-------------------------------------------------------------------------
// 실행시 호출 되는 함수
//-------------------------------------------------------------------------
scwin.f_Save = async function(){

	// 필수입력 사항 확인
    let ret = await $c.gus.cfValidate([ica_FromDate]);
    if (!ret) {
        return false;
    }

  	if (!await scwin.f_JobCloseYN()) return;

	if (await $c.win.confirm("예산생성을 실행 하시겠습니까?") ) {

		dma_searchBudgetCreate.set("budgetYm",ica_FromDate.getValue().trim());
        $c.sbm.execute(sbm_saveBudgetCreate);	
	}

}

//-------------------------------------------------------------------------
// 마감체크
//-------------------------------------------------------------------------
scwin.f_JobCloseYN = async function() {
	//cfJobCloseYN(마감요청구분,마감년월,마감일,작업번호,관리번호,리턴구분);
	// 선행작업 마감여부 체크 
	let isClose = await udc_comChkRes.cfJobCloseYN("CUR",ica_FromDate.getValue().trim()+"00","00",ACConstants.CLOSE_BUDGET_CREATION,"0","ARR","",ed_coCd.getValue());

	// 선행마감 작업에 대한 검사
	if ( isClose[3] == "PRE" ) {
		if (isClose[0]=="1") {
			await $c.win.alert("선행작업 "+isClose[2]+"이 미마감되어서 현재 작업을 진행할 수 없습니다.");
			return false;
		} else if (isClose[0]=="0") {
			await $c.win.alert("선행작업 "+isClose[2]+"이 마감작업중이어서 현재 작업을 진행할 수 없습니다.");
			return false;
		} 
	} 

	// 해당마감 작업에 대한 검사
	if ( isClose[3] == "CUR" ) {
		if(isClose[0]=="0"){
			await $c.win.alert(isClose[2] + "(이)가 마감중입니다.");
			return false;
		 }else if(isClose[0]=="2"){
			await $c.win.alert(isClose[2] + "(이)가 마감완료가 되었습니다");
			return false;
		}else {
			return true;
		}
	}
};

//-------------------------------------------							
// 그리드 데이터 엑셀로 다운							
//-------------------------------------------	
scwin.f_runExcel = async function() {
    let totCnt = ds_budgetCreate.getRowCount();
    let sheetTitle = "예산생성내역";

    if (totCnt > 0) {
        let confirmResult = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (confirmResult) {
            const options = {
                fileName: sheetTitle + ".xlsx",
                sheetName: sheetTitle,
                columnMove:true,
            };
            $c.data.downloadGridViewExcel(gr_budgetCreate, options);
        }
    } else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};

//-------------------------------------------							
// 그리드 높이 늘리고 줄이기							
//-------------------------------------------		
scwin.f_grdHeiht = function (gridNm, size) {

    let strHeight = gridNm.style.height;
    let intHeight = parseInt(strHeight.replace("px", ""));
    intHeight = intHeight + size;
    if (intHeight > 0) {
        gridNm.style.height = intHeight + "px";
    }
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search);
};

scwin.sbm_saveBudgetCreate_submitdone = async function (e) {
    if(e.responseJSON.resultDataSet[0].Code != -1){
        await $c.win.alert(MSG_CM_INF_001);
        ds_budgetCreate.reform();
        scwin.f_Retrieve();
    }
};

scwin.sbm_searchBudgetCreate_submitdone = async function (e) {
    // 조회된 건수를 Grid 왼쪽 하단에 표시한다.
    let rowCnt = ds_budgetCreate.getRowCount();
    totalRows.setValue(rowCnt);
    gr_budgetCreate.setFocusedCell(0, 0);
    if( rowCnt == 0 ){
        await $c.win.alert(MSG_CM_ERR_003);
    }
};

scwin.udc_dongbuGroupCompanyInfo_onblurCodeEvent = function (e) {
    if (ed_coCd.getValue() != ""){
        scwin.f_PopUpCompanyInfo('T');
    }
    else{
        ed_coNm.setValue("");
    }
};

scwin.udc_dongbuGroupCompanyInfo_onclickEvent = function (e) {
    scwin.f_PopUpCompanyInfo('F');
};
